 1→import { createORPCClient } from "@orpc/client";
 2→import { RPCLink } from "@orpc/client/fetch";
 3→import type { ContractRouterClient } from "@orpc/contract";
 4→import { createTanstackQueryUtils } from "@orpc/tanstack-query";
 5→import type { contract } from "@rudel/api-routes";
 6→
 7→const link = new RPCLink({
 8→	url: new URL("/rpc", window.location.origin).href,
 9→	fetch: (input, init) => fetch(input, { ...init, credentials: "include" }),
10→});
11→
12→export const client: ContractRouterClient<typeof contract> =
13→	createORPCClient(link);
14→
15→export const orpc = createTanstackQueryUtils(client);
16→

